-- Older rows predate the scalar browser_name column and only carry the
-- browser JSON blob; backfill so read paths can rely on the scalar.
UPDATE test_runs_cases
SET browser_name = json_extract(browser, '$.projectName')
WHERE browser_name IS NULL
	AND browser IS NOT NULL
	AND json_extract(browser, '$.projectName') IS NOT NULL;

CREATE TABLE `case_payloads` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`project_id` integer NOT NULL,
	`hash` text NOT NULL,
	`content` text NOT NULL,
	`size` integer NOT NULL,
	`created_at` integer NOT NULL,
	FOREIGN KEY (`project_id`) REFERENCES `projects`(`id`) ON UPDATE no action ON DELETE cascade
);

CREATE UNIQUE INDEX `idx_case_payloads_project_hash` ON `case_payloads` (`project_id`,`hash`);
ALTER TABLE `test_runs_cases` ADD `aria_snapshot_payload_id` integer REFERENCES case_payloads(id);
ALTER TABLE `test_runs_cases` ADD `test_source_payload_id` integer REFERENCES case_payloads(id);
ALTER TABLE `test_runs_cases` ADD `test_source_frames_payload_id` integer REFERENCES case_payloads(id);
CREATE INDEX `idx_trc_aria_payload` ON `test_runs_cases` (`aria_snapshot_payload_id`) WHERE aria_snapshot_payload_id IS NOT NULL;
CREATE INDEX `idx_trc_source_payload` ON `test_runs_cases` (`test_source_payload_id`) WHERE test_source_payload_id IS NOT NULL;
CREATE INDEX `idx_trc_frames_payload` ON `test_runs_cases` (`test_source_frames_payload_id`) WHERE test_source_frames_payload_id IS NOT NULL;

CREATE TABLE `markers` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
	`project_id` integer NOT NULL,
	`occurred_at` integer NOT NULL,
	`label` text NOT NULL,
	`description` text,
	`category` text DEFAULT 'event' NOT NULL,
	`environment` text,
	`source` text DEFAULT 'manual' NOT NULL,
	`run_id` integer,
	`created_at` integer NOT NULL,
	`updated_at` integer NOT NULL,
	FOREIGN KEY (`project_id`) REFERENCES `projects`(`id`) ON UPDATE no action ON DELETE cascade,
	FOREIGN KEY (`run_id`) REFERENCES `test_runs`(`id`) ON UPDATE no action ON DELETE set null
);

CREATE INDEX `idx_markers_project_id` ON `markers` (`project_id`);
CREATE INDEX `idx_markers_project_occurred` ON `markers` (`project_id`,`occurred_at`);

CREATE INDEX `idx_markers_run_id` ON `markers` (`run_id`);

