INSERT INTO failure_diagnoses (id, cluster_id, scope, status, provider, model, category, confidence, summary, root_cause, details, error, input_tokens, output_tokens, duration_ms, created_at, updated_at) VALUES (1, 1, 'cluster', 'completed', 'demo', 'demo-simulated', 'infrastructure', 'high', 'Checkout Pay button click times out — the payment form renders slowly on CI and the click races the render.', 'The click is interrupted by the 30 000 ms test timeout because the Pay button is present but not yet interactive. A recent commit added a third-party payment SDK fetched before the form is enabled; on a loaded CI runner that pushes interactivity past the timeout. Combined with CI variability this fails intermittently.', '{"confidenceScore":82,"severity":"high","affectedArea":"checkout / payment","hypotheses":[{"category":"infrastructure","likelihood":82,"rootCause":"Slow CI runner renders the payment form too late; the click exceeds the 30s test timeout before the button becomes interactive.","evidence":["Failure rate correlates with high-load CI runs [recurrenceFlakiness]","The call log shows the button resolved but disabled at click time [executionError]"]},{"category":"test-bug","likelihood":38,"rootCause":"The payment helper clicks without an explicit wait for the quote to resolve.","evidence":["No waitForLoadState/waitFor precedes the click in fillPaymentDetails [testSource]"]}],"evidence":["The test timeout interrupts locator.click in both affected tests [executionError]","The SCM diff adds a third-party payment SDK fetched before the form is enabled [scmInvestigation]","The checkout quote request takes 28s on failing runs [networkRequests]","The full call stack from the trace pins the timeout inside the checkout flow helper [traceCallStack]","Recurs on high-load CI runs [recurrenceFlakiness]"],"investigationSteps":["Re-run the cluster on a low-load runner to confirm CI variability is the driver","Check whether the payment form fires a network-idle event before becoming interactive"],"preventionTips":["Await page.waitForLoadState(\"networkidle\") before interacting with dynamically loaded payment forms","Add a CI-aware timeout multiplier for payment-related actions"],"suggestedFix":{"description":"Wait for the network to settle before clicking, so the click no longer races the third-party form render.","file":"tests/helpers/payment.ts","code":null,"patch":"--- a/tests/helpers/payment.ts\n+++ b/tests/helpers/payment.ts\n@@ -15,2 +15,3 @@\n   // Pay stays disabled until the async price quote resolves\n+  await page.waitForLoadState(''networkidle'');\n   await page.getByRole(''button'', { name: ''Pay'' }).click();"},"patchValidation":{"status":"applies","filesChecked":1,"filesInPatch":1,"errors":[]},"pipeline":[{"role":"research","model":"demo-research","inputTokens":744,"outputTokens":180,"cacheCreationInputTokens":0,"cacheReadInputTokens":0},{"role":"diagnosis","model":"demo-simulated","inputTokens":1240,"outputTokens":380,"cacheCreationInputTokens":496,"cacheReadInputTokens":620}],"autoSelectedCommits":["a1b2c3d4e5f60718293a4b5c6d7e8f90a1b2c3d4"],"selectedCommitShas":null,"additionalContext":null}', NULL, 1984, 560, 2850, 1745572320, 1745572320);
INSERT INTO failure_diagnoses (id, cluster_id, scope, status, provider, model, category, confidence, summary, root_cause, details, error, input_tokens, output_tokens, duration_ms, created_at, updated_at) VALUES (2, 3, 'cluster', 'completed', 'demo', 'demo-simulated', 'app-bug', 'high', 'POST /auth/login returns HTTP 500 — the login handler dereferences a null user after the auth refactor.', 'The assertion fails because the endpoint responds 500 instead of 200. A recent auth refactor changed verifyCredentials to return null (rather than throw) for a missing user, and the login handler then reads user.id on the null path — an unhandled exception that surfaces as a 500.', '{"confidenceScore":90,"severity":"blocker","affectedArea":"authentication / login","hypotheses":[{"category":"app-bug","likelihood":90,"rootCause":"The login handler dereferences a null user after the auth refactor, throwing and returning HTTP 500.","evidence":["Expected 200 / Received 500 in two separate auth test cases [executionError]","Backend server logs show an unhandled TypeError on the request [serverLogs]","The failure started after the auth refactor commit [scmInvestigation]"]}],"evidence":["Received 500 where 200 was expected across two auth tests [executionError]","Server logs capture the 5xx and the null-dereference stack on the failing request [serverLogs]","Began appearing after the \"simplify auth flow\" commit [scmInvestigation]"],"investigationSteps":["Inspect the server stack trace behind the 500 on POST /auth/login","Confirm the null-user branch in the refactored handler"],"preventionTips":["Add integration tests that exercise the auth endpoint with missing/invalid users","Add error monitoring on 5xx responses for the /auth/login route"],"suggestedFix":{"description":"Restore the missing-user guard the refactor dropped, so the handler returns 401 instead of dereferencing null.","file":"src/routes/auth.ts","code":null,"patch":"--- a/src/routes/auth.ts\n+++ b/src/routes/auth.ts\n@@ -8,2 +8,5 @@\n   const user = await verifyCredentials(email, password);\n+  if (!user) {\n+    return res.status(401).json({ error: ''Invalid credentials'' });\n+  }\n   const token = signSession(user.id);"},"patchValidation":{"status":"applies","filesChecked":1,"filesInPatch":1,"errors":[]},"pipeline":[{"role":"research","model":"demo-research","inputTokens":588,"outputTokens":180,"cacheCreationInputTokens":0,"cacheReadInputTokens":0},{"role":"diagnosis","model":"demo-simulated","inputTokens":980,"outputTokens":310,"cacheCreationInputTokens":392,"cacheReadInputTokens":490}],"autoSelectedCommits":["f1e2d3c4b5a6079887766554433221100ffeeddc"],"selectedCommitShas":null,"additionalContext":null}', NULL, 1568, 490, 2100, 1745571900, 1745571900);
INSERT INTO failure_diagnoses (id, cluster_id, scope, status, provider, model, category, confidence, summary, root_cause, details, error, input_tokens, output_tokens, duration_ms, created_at, updated_at) VALUES (3, 6, 'cluster', 'completed', 'demo', 'demo-simulated', 'test-flakiness', 'medium', 'Strict-mode violation — getByRole(''button'') matches multiple button variants rendered on the components page.', 'getByRole(''button'') resolves to 3 elements because the components page now renders primary, disabled and loading variants side by side (added in a recent commit). Playwright''s strict mode throws on the ambiguous match; the locator needs scoping by name or container.', '{"confidenceScore":66,"severity":"medium","affectedArea":"UI components / button","hypotheses":[{"category":"test-bug","likelihood":66,"rootCause":"getByRole(''button'') matches 3 rendered button variants; the locator must be scoped by name or container.","evidence":["Strict-mode violation resolving to multiple elements [executionError]","The ARIA snapshot shows several button nodes on the page [ariaSnapshot]","Locator healing offers a scoped, higher-stability alternative [locatorHealing]"]}],"evidence":["Deterministic strict-mode violation, not intermittent [recurrenceFlakiness]","Three button elements rendered by design (primary, disabled, loading) [ariaSnapshot]","A name-scoped locator disambiguates the match [locatorHealing]"],"investigationSteps":["Confirm the page intentionally renders multiple button variants","Pick a scoping strategy (name filter or container) with the component owner"],"preventionTips":["Scope locators to a container when multiple matches are expected","Add data-testid attributes to disambiguate similar components"],"suggestedFix":{"description":"Scope the locator to a specific variant with a name filter so it matches exactly one button.","file":"tests/ui/button.spec.ts","code":null,"patch":"--- a/tests/ui/button.spec.ts\n+++ b/tests/ui/button.spec.ts\n@@ -9,3 +9,3 @@\n     // The gallery renders every variant side by side\n-    await page.getByRole(''button'').click();\n+    await page.getByRole(''button'', { name: ''Primary'' }).click();\n     await expect(page.locator(''.btn-primary'')).toHaveClass(/is-active/);"},"patchValidation":{"status":"applies","filesChecked":1,"filesInPatch":1,"errors":[]},"pipeline":[{"role":"research","model":"demo-research","inputTokens":522,"outputTokens":180,"cacheCreationInputTokens":0,"cacheReadInputTokens":0},{"role":"diagnosis","model":"demo-simulated","inputTokens":870,"outputTokens":290,"cacheCreationInputTokens":348,"cacheReadInputTokens":435}],"autoSelectedCommits":["3a4b5c6d7e8f90a1b2c3d4e5f60718293a4b5c6d"],"selectedCommitShas":null,"additionalContext":null}', NULL, 1392, 470, 1950, 1745514545, 1745514545);
INSERT INTO failure_diagnoses (id, cluster_id, scope, status, provider, model, category, confidence, summary, root_cause, details, error, input_tokens, output_tokens, duration_ms, created_at, updated_at) VALUES (4, 7, 'cluster', 'completed', 'demo', 'demo-simulated', 'infrastructure', 'high', 'Mobile page navigation times out — page.goto exceeds 30s on Mobile Safari because the landing page ships a heavy hero image.', 'page.goto exceeds the 30 000 ms navigation timeout during the initial load. A recent commit added a full-bleed, unoptimized hero image; on throttled mobile CI networks the load never completes inside the default timeout.', '{"confidenceScore":78,"severity":"high","affectedArea":"mobile navigation","hypotheses":[{"category":"infrastructure","likelihood":78,"rootCause":"Heavy unoptimized assets push mobile page load past the goto timeout on CI networks.","evidence":["Timeout occurs on the main navigation load, not a later interaction [executionError]","Only affects the Mobile Safari browser profile [browserDistribution]"]},{"category":"environment","likelihood":34,"rootCause":"CI network throttling specific to the mobile project profile.","evidence":["The hero image request alone takes ~28s on failing runs [networkRequests]"]}],"evidence":["page.goto TimeoutError on the main navigation load [executionError]","Only the Mobile Safari profile is affected [browserDistribution]","The SCM diff adds a large full-bleed hero image [scmInvestigation]"],"investigationSteps":["Measure page weight and largest-contentful-paint on the mobile profile","Compare goto timing on local mobile emulation vs CI"],"preventionTips":["Set browser-specific navigation timeouts via Playwright config projects","Optimize landing-page assets for mobile (responsive images, lazy-loading)"],"suggestedFix":{"description":"Raise the navigation timeout for the mobile profile while the asset weight is addressed.","file":"tests/mobile/navigation.spec.ts","code":null,"patch":"--- a/tests/mobile/navigation.spec.ts\n+++ b/tests/mobile/navigation.spec.ts\n@@ -4,3 +4,3 @@\n   test(''Tab bar navigation works correctly'', async ({ page }) => {\n-    await page.goto(''https://m.shop.example.com/'');\n+    await page.goto(''https://m.shop.example.com/'', { timeout: 60000 });\n     await page.getByRole(''tab'', { name: ''Browse'' }).click();"},"patchValidation":{"status":"applies","filesChecked":1,"filesInPatch":1,"errors":[]},"pipeline":[{"role":"research","model":"demo-research","inputTokens":660,"outputTokens":180,"cacheCreationInputTokens":0,"cacheReadInputTokens":0},{"role":"diagnosis","model":"demo-simulated","inputTokens":1100,"outputTokens":340,"cacheCreationInputTokens":440,"cacheReadInputTokens":550}],"autoSelectedCommits":["6d7e8f90a1b2c3d4e5f60718293a4b5c6d7e8f90"],"selectedCommitShas":null,"additionalContext":null}', NULL, 1760, 520, 2650, 1745572680, 1745572680);
INSERT INTO failure_diagnoses (id, cluster_id, scope, status, provider, model, category, confidence, summary, root_cause, details, error, input_tokens, output_tokens, duration_ms, created_at, updated_at) VALUES (5, 10, 'cluster', 'completed', 'demo', 'demo-simulated', 'app-bug', 'high', 'Users table renders 50 rows instead of 25 — server-driven pagination shipped with the API default page size.', 'The row-count assertion fails deterministically: the users endpoint now returns 50 rows per page. The server-driven pagination change replaced the dashboard page size (25) with the API default (50), so the table renders two pages worth of rows and the test correctly catches the regression.', '{"confidenceScore":88,"severity":"medium","affectedArea":"users table / pagination","hypotheses":[{"category":"app-bug","likelihood":88,"rootCause":"listUsers now queries with PAGE_SIZE 50 — the API default — instead of the dashboard page size 25.","evidence":["Expected 26 rows (header + 25), received 51 — exactly two pages plus the header [executionError]","The users API request returns 50 records [networkRequests]","The pagination change shipped in the suspect commit [scmInvestigation]"]},{"category":"test-bug","likelihood":20,"rootCause":"The new page size is intentional and the expected count is stale.","evidence":["No product note accompanies the page-size change [scmInvestigation]"]}],"evidence":["Deterministic 26-vs-51 row count mismatch [executionError]","GET /api/users?page=1 returns 50 records on failing runs [networkRequests]","The \"server-driven pagination\" commit changed PAGE_SIZE from 25 to 50 [scmInvestigation]"],"investigationSteps":["Confirm the intended dashboard page size with the design system (table density assumes 25)","Check other tables consuming the same endpoint for the same regression"],"preventionTips":["Keep page-size constants in one shared module consumed by both API and UI","Assert on user-visible pagination controls in addition to raw row counts"],"suggestedFix":{"description":"Restore the dashboard page size the server-driven pagination change overrode.","file":"src/server/users.ts","code":null,"patch":"--- a/src/server/users.ts\n+++ b/src/server/users.ts\n@@ -5,3 +5,3 @@\n // worth of rows at once.\n-const PAGE_SIZE = 50;\n+const PAGE_SIZE = 25;\n "},"patchValidation":{"status":"applies","filesChecked":1,"filesInPatch":1,"errors":[]},"pipeline":[{"role":"research","model":"demo-research","inputTokens":606,"outputTokens":180,"cacheCreationInputTokens":0,"cacheReadInputTokens":0},{"role":"diagnosis","model":"demo-simulated","inputTokens":1010,"outputTokens":330,"cacheCreationInputTokens":404,"cacheReadInputTokens":505}],"autoSelectedCommits":["c4d5e6f708192a3b4c5d6e7f8091a2b3c4d5e6f7"],"selectedCommitShas":null,"additionalContext":null}', NULL, 1620, 505, 2240, 1745541427, 1745541427);
INSERT INTO failure_diagnosis_versions (id, diagnosis_id, cluster_id, scope, test_runs_case_id, status, provider, model, category, confidence, summary, root_cause, details, error, input_tokens, output_tokens, duration_ms, context_sha, created_at) VALUES (1, 1, 1, 'cluster', NULL, 'completed', 'demo', 'demo-simulated', 'test-bug', 'medium', 'Earlier take: likely a missing explicit wait in the payment helper before the Pay click.', 'Initial assessment attributed the timeout purely to a missing explicit wait in the payment helper, before the SCM diff surfaced the newly added third-party payment SDK that delays interactivity.', '{"confidenceScore":58,"severity":"medium","affectedArea":"checkout / payment","hypotheses":[{"category":"test-bug","likelihood":58,"rootCause":"The helper clicks the Pay button without waiting for it to become interactive.","evidence":["No waitFor precedes the click [testSource]"]}],"evidence":["Intermittent timeouts on locator.click [recurrenceFlakiness]"],"investigationSteps":["Check CI load at failure time"],"preventionTips":["Await the target before interacting"],"suggestedFix":{"description":"Add an explicit wait before clicking the Pay button.","file":"tests/helpers/payment.ts","code":null,"patch":null}}', NULL, 640, 210, 1700, NULL, 1745537400);
